fn env_var_functions_unix() {
  if cfg!(windows) {
    return;
  }
  Test::new()
    .justfile(
      r"
p := env_var('USER')
b := env_var_or_default('ZADDY', 'HTAP')
x := env_var_or_default('XYZ', 'ABC')

foo:
  /usr/bin/env echo '{{p}}' '{{b}}' '{{x}}'
",
    )
    .stdout(format!("{} HTAP ABC\n", env::var("USER").unwrap()).as_str())

